239 std::string Regex::escape(StringRef String) {
240   std::string RegexStr;
241   for (char C : String) {
242     if (strchr(RegexMetachars, C))
243       RegexStr += '\\';
244     RegexStr += C;
245   }
246 
247   return RegexStr;
