1165     for (VPRecipeBase &NewR : *NewBB)
1166       for (unsigned I = 0, E = NewR.getNumOperands(); I != E; ++I) {
1167         VPValue *NewOp = Old2NewVPValues.lookup(NewR.getOperand(I));
1168         NewR.setOperand(I, NewOp);
