2181 /// Sink users of \p FOR after the recipe defining the previous value \p
2182 /// Previous of the recurrence. \returns true if all users of \p FOR could be
2183 /// re-arranged as needed or false if it is not possible.
2184 static bool
2185 sinkRecurrenceUsersAfterPrevious(VPFirstOrderRecurrencePHIRecipe *FOR,
2186                                  VPRecipeBase *Previous,
2187                                  VPDominatorTree &VPDT) {
2188   // Collect recipes that need sinking.
2189   SmallVector<VPRecipeBase *> WorkList;
2190   SmallPtrSet<VPRecipeBase *, 8> Seen;
2191   Seen.insert(Previous);
2192   auto TryToPushSinkCandidate = [&](VPRecipeBase *SinkCandidate) {
2193     // The previous value must not depend on the users of the recurrence phi. In
2194     // that case, FOR is not a fixed order recurrence.
2195     if (SinkCandidate == Previous)
2196       return false;
2197 
2198     if (isa<VPHeaderPHIRecipe>(SinkCandidate) ||
2199         !Seen.insert(SinkCandidate).second ||
2200         VPDT.properlyDominates(Previous, SinkCandidate))
2201       return true;
2202 
2203     if (cannotHoistOrSinkRecipe(*SinkCandidate))
2204       return false;
2205 
2206     WorkList.push_back(SinkCandidate);
2207     return true;
2208   };
2209 
2210   // Recursively sink users of FOR after Previous.
2211   WorkList.push_back(FOR);
2212   for (unsigned I = 0; I != WorkList.size(); ++I) {
2213     VPRecipeBase *Current = WorkList[I];
2214     assert(Current->getNumDefinedValues() == 1 &&
2215            "only recipes with a single defined value expected");
2216 
2217     for (VPUser *User : Current->getVPSingleValue()->users()) {
2218       if (!TryToPushSinkCandidate(cast<VPRecipeBase>(User)))
2219         return false;
2220     }
2221   }
2222 
2223   // Keep recipes to sink ordered by dominance so earlier instructions are
2224   // processed first.
2225   sort(WorkList, [&VPDT](const VPRecipeBase *A, const VPRecipeBase *B) {
2226     return VPDT.properlyDominates(A, B);
2227   });
2228 
2229   for (VPRecipeBase *SinkCandidate : WorkList) {
2230     if (SinkCandidate == FOR)
2231       continue;
2232 
2233     SinkCandidate->moveAfter(Previous);
2234     Previous = SinkCandidate;
2235   }
2236   return true;
